import { GTProp, Variable, VariableType, JsxChildren, CustomMapping } from 'generaltranslation/types';
export { GTProp } from 'generaltranslation/types';
import React, { ReactNode } from 'react';
import { GT } from 'generaltranslation';
import { InlineTranslationOptions, DictionaryTranslationOptions } from 'gt-i18n/types';
export { DictionaryTranslationOptions, GTFunctionType, InlineTranslationOptions, MFunctionType, RuntimeTranslationOptions } from 'gt-i18n/types';

/**
 * For dictionaries, we have Entry and MetaEntry
 */
type Entry = string;
type MetaEntry = {
    $context?: string;
    $maxChars?: number;
    $_hash?: string;
    [key: string]: unknown;
};
type DictionaryEntry = Entry | [Entry] | [Entry, MetaEntry];
type Dictionary = {
    [key: string]: Dictionary | DictionaryEntry;
} | (Dictionary | DictionaryEntry)[];
type FlattenedDictionary = {
    [key: string]: DictionaryEntry;
};
/**
 * Translated content types
 */
type TranslatedElement = {
    i?: number;
    d?: GTProp;
    c?: TranslatedChildren;
};
type TranslatedChild = TranslatedElement | string | Variable;
type TranslatedChildren = TranslatedChild | TranslatedChild[];
type Translations = {
    [hash: string]: TranslatedChildren | null;
};
/**
 * @deprecated use {@link Dictionary}
 */
type DictionaryContent = string;
/**
 * @deprecated use {@link Dictionary}
 */
type DictionaryObject = {
    [id: string]: DictionaryContent;
};
type LocalesDictionary = {
    [locale: string]: DictionaryObject;
};
type CustomLoader = (locale: string) => Promise<any>;
type RenderMethod = 'skeleton' | 'replace' | 'default';
type VariableProps = {
    variableType: VariableType;
    variableValue: any;
    variableOptions: Intl.NumberFormatOptions | Intl.DateTimeFormatOptions;
    variableName: string;
};
type RenderVariable = ({ variableType, variableValue, variableOptions, locales, }: Omit<VariableProps, 'variableName'> & {
    locales: string[];
}) => React.JSX.Element;
type _Message = {
    message: string;
    $id?: string;
    $context?: string;
    $maxChars?: number;
    $_hash?: string;
};
type _Messages = _Message[];

type TranslateIcuCallback = (params: {
    source: string;
    targetLocale: string;
    metadata: {
        hash: string;
        context?: string;
        maxChars?: number;
    } & Record<string, any>;
}) => Promise<TranslatedChildren>;
type TranslateChildrenCallback = (params: {
    source: JsxChildren | undefined;
    targetLocale: string;
    metadata: {
        hash: string;
        context?: string;
        maxChars?: number;
    } & Record<string, any>;
}) => Promise<TranslatedChildren>;

type GTContextType = {
    gt: GT;
    registerIcuForTranslation: TranslateIcuCallback;
    registerJsxForTranslation: TranslateChildrenCallback;
    _gtFunction: (message: string, options?: InlineTranslationOptions, preloadedTranslations?: Translations) => string;
    _mFunction: <T extends string | null | undefined>(encodedMsg: T, options?: Record<string, any>, preloadedTranslations?: Translations) => T extends string ? string : T;
    _filterMessagesForPreload: (_messages: _Messages) => _Messages;
    _preloadMessages: (_messages: _Messages) => Promise<Translations>;
    _dictionaryFunction: (id: string, options?: DictionaryTranslationOptions) => string;
    _dictionaryObjFunction: (id: string, idWithParent: string, options?: DictionaryTranslationOptions) => Dictionary | DictionaryEntry | string | undefined;
    developmentApiEnabled: boolean;
    locale: string;
    locales: string[];
    setLocale: (locale: string) => void;
    defaultLocale: string;
    region: string | undefined;
    setRegion: (region: string | undefined) => void;
    translations: Translations | null;
    translationRequired: boolean;
    dialectTranslationRequired: boolean;
    renderSettings: {
        method: RenderMethod;
        timeout?: number;
    };
    projectId?: string;
};

type AuthFromEnvParams = {
    projectId?: string;
    devApiKey?: string;
};
type AuthFromEnvReturn = {
    projectId: string;
    devApiKey?: string;
};

type UseDetermineLocaleParams = {
    defaultLocale: string;
    locales: string[];
    enableI18n: boolean;
    locale?: string;
    localeCookieName?: string;
    ssr?: boolean;
    customMapping?: CustomMapping;
};
type UseDetermineLocaleReturn = [string, (locale: string) => void];

type UseRegionStateParams = {
    _region: string | undefined;
    ssr: boolean;
    regionCookieName: string;
};
type UseRegionStateReturn = {
    region: string | undefined;
    setRegion: (region: string | undefined) => void;
};
type UseEnableI18nParams = {
    enableI18n: boolean;
    enableI18nCookieName: string;
    enableI18nLoaded?: boolean;
    ssr: boolean;
};
type UseEnableI18nReturn = {
    enableI18n: boolean;
};

type LocaleSelectorProps = {
    locales?: string[];
    customNames?: {
        [key: string]: string;
    };
    customMapping?: CustomMapping;
    [key: string]: any;
};
type RegionSelectorProps<Regions extends string[]> = {
    regions?: Regions;
    placeholder?: ReactNode;
    customMapping?: CustomMapping;
    prioritizeCurrentLocaleRegion?: boolean;
    sortRegionsAlphabetically?: boolean;
};

type GTConfig = {
    projectId?: string;
    devApiKey?: string;
    locales?: string[];
    defaultLocale?: string;
    dictionary?: string;
    runtimeUrl?: string | null;
    cacheUrl?: string | null;
    renderSettings?: {
        method: RenderMethod;
        timeout?: number;
    };
    _versionId?: string;
    ssr?: boolean;
    localeCookieName?: string;
    customMapping?: CustomMapping;
    modelProvider?: string;
    enableI18n?: boolean;
};
type InternalGTProviderProps = {
    children?: React.ReactNode;
    projectId?: string;
    devApiKey?: string;
    dictionary?: any;
    locales?: string[];
    defaultLocale?: string;
    locale?: string;
    region?: string;
    cacheUrl?: string | null;
    runtimeUrl?: string | null;
    renderSettings?: {
        method: RenderMethod;
        timeout?: number;
    };
    _versionId?: string;
    ssr?: boolean;
    localeCookieName?: string;
    translations?: Translations | null;
    loadDictionary?: CustomLoader;
    loadTranslations?: CustomLoader;
    config?: GTConfig;
    fallback?: React.ReactNode;
    customMapping?: CustomMapping;
    modelProvider?: string;
    environment: 'development' | 'production' | 'test';
    enableI18n?: boolean;
    /** Flag to indicate if the enableI18n flag is finished loading asynchronously */
    enableI18nLoaded?: boolean;
    readAuthFromEnv: (params: AuthFromEnvParams) => AuthFromEnvReturn;
    useDetermineLocale: (params: UseDetermineLocaleParams) => UseDetermineLocaleReturn;
    useRegionState: (params: UseRegionStateParams) => UseRegionStateReturn;
    useEnableI18n?: (params: UseEnableI18nParams) => UseEnableI18nReturn;
    [key: string]: any;
};

export type { AuthFromEnvParams, AuthFromEnvReturn, CustomLoader, Dictionary, DictionaryContent, DictionaryEntry, DictionaryObject, Entry, FlattenedDictionary, GTConfig, GTContextType, InternalGTProviderProps, LocaleSelectorProps, LocalesDictionary, MetaEntry as Metadata, RegionSelectorProps, RenderMethod, RenderVariable, TranslatedChildren, Translations, UseDetermineLocaleParams, UseDetermineLocaleReturn, UseEnableI18nParams, UseEnableI18nReturn, UseRegionStateParams, UseRegionStateReturn, VariableProps, _Message, _Messages };
